const chatInput = $json.chatInput || '';
const intent = $json.intentHint || 'general';
const book = $json.selectedBook?.title || null;
let reply = 'I can help with books, reviews, and pricing.';

if (intent === 'reviews' && book) {
  reply = `${book} has positive reader feedback overall. If you want, I can also help compare it with similar books.`;
} else if (intent === 'browse' && book) {
  reply = `${book} is available for $${$json.selectedBook?.price ?? 'N/A'}. You can ask me for reviews or similar recommendations.`;
} else if (book) {
  reply = `${book} is currently priced at $${$json.selectedBook?.price ?? 'N/A'}. You can ask for reviews, stock status, or next steps.`;
}

return [{ json: { reply } }];
